const Dev = "ASSET_ID_START_MET_36 ";
const PAYLOAD_TYPE = {
    T1: { header: 0x6d, size_min: 8, size_max: 46, name: "T1" },
    T2: { header: 0x6e, size: 15, name: "T2" },
    TT1: { header: 0x2e, size: 22, name: "TT1" },
    TT6: { header: 0x2f, size: 42, name: "TT6" },
    START: { header: 0x01, size: 3, name: "START" }
};

function u32_be(payload, offset) {
    return ((payload[offset] & 0xFF) << 24) |
        ((payload[offset + 1] & 0xFF) << 16) |
        ((payload[offset + 2] & 0xFF) << 8) |
        (payload[offset + 3] & 0xFF);
}
function u16_be(payload, offset) {
    return ((payload[offset] & 0xFF) << 8) | (payload[offset + 1] & 0xFF);
}

function find_message_type(payload) {
    if (!payload || payload.length < 1) return null;
    switch (payload[0]) {
        case PAYLOAD_TYPE.T1.header:
            if (payload.length >= PAYLOAD_TYPE.T1.size_min && payload.length <= PAYLOAD_TYPE.T1.size_max) return PAYLOAD_TYPE.T1.name;
            break;
        case PAYLOAD_TYPE.TT1.header:
            if (payload.length === PAYLOAD_TYPE.TT1.size) return PAYLOAD_TYPE.TT1.name;
            break;
        case PAYLOAD_TYPE.TT6.header:
            if (payload.length === PAYLOAD_TYPE.TT6.size) return PAYLOAD_TYPE.TT6.name;
            break;
        case PAYLOAD_TYPE.T2.header:
            if (payload.length === PAYLOAD_TYPE.T2.size) return PAYLOAD_TYPE.T2.name;
            break;
        case PAYLOAD_TYPE.START.header:
            if (payload.length === PAYLOAD_TYPE.START.size) return PAYLOAD_TYPE.START.name;
            break;
    }
    return null;
}

function decode_T1(payload, recvTime) {
    const data = {};
    data.time_step = payload[1];
    data.index = u32_be(payload, 2) / 10;

    data.increments = [];
    data.indexes = [];

    const nb_values_in_payload = (payload.length - 6) / 2;


    for (let i = 0; i < nb_values_in_payload; i++) {
        const inc = u16_be(payload, 6 + 2 * i) / 10;

        if (recvTime != null) {
            const d = new Date(recvTime);
            d.setSeconds(d.getSeconds() - ((nb_values_in_payload - i) * data.time_step * 60));
            data.increments.push([d.toISOString(), inc]);
        } else {
            data.increments.push(inc);
        }
    }

    let idx = data.index;
    for (let i = nb_values_in_payload; i >= 0; i--) {
        if (recvTime != null) {
            const d = new Date(recvTime);
            d.setSeconds(d.getSeconds() - ((nb_values_in_payload - i) * data.time_step * 60));
            data.indexes.unshift([d.toISOString(), idx]);
            if (i !== 0) idx -= data.increments[i - 1][1];
        } else {
            data.indexes.unshift(idx);
            if (i !== 0) idx -= data.increments[i - 1];
        }
    }

    return data;
}

function decode_T2(payload) {
    const data = {};
    data.number_of_starts = payload[1];
    data.param_id = payload[4];
    data.firmware_version = payload[5];
    data.index = u32_be(payload, 8) / 10;
    data.time_step = payload[12];
    data.number_of_values = payload[13];
    data.redundancy = payload[14];
    return data;
}

let mid = global.get("mid") || 0;



const PulseConversionValue = 1;

const idMapping = {
    // "battery": 4900, // bewust niet gebruiken als het niet binnenkomt

    "humidity": 6900,
    "temperature": 6800,
    "water": 5600, // dit is gas maar meter stuurt 'water'

    "bandwidth": 5100,
    "spreadfactor": 5200, 
    "freq": 5300,
    "snr": 5400,
    "rssi": 5500
};
const normalizedIdMapping = Object.create(null);
for (const [k, v] of Object.entries(idMapping)) normalizedIdMapping[k.toLowerCase()] = v;

let result = {
    MID: mid,
    D: [
        {
            Dev: Dev,
            ED: [],
            MD: []
        }
    ]
};

// Timestamp
const recvTime = msg.time || msg.recvTime || msg.received_at || null;
if (recvTime) {
    const d = new Date(recvTime);
    if (!isNaN(d.getTime())) result.D[0].TS = d.toISOString();
}

let b64 = null;

if (msg.payload && typeof msg.payload === "object" && typeof msg.payload.payload === "string") {
    b64 = msg.payload.payload.trim();
}
else if (typeof msg.payload === "string") {
    b64 = msg.payload.trim();
}

if (!b64) {
    node.warn("No base64 payload found (expected msg.payload string or msg.payload.payload).");
} else {
    let buf;
    try {
        buf = Buffer.from(b64, "base64");
    } catch (e) {
        node.warn("Invalid base64 payload");
        buf = null;
    }

    if (buf) {
        const bytes = Array.from(buf);

        const msgType = find_message_type(bytes);

        if (!msgType) {
            node.warn("Unknown payload type/size. hex=" + buf.toString("hex"));
        } else {
            if (msgType === PAYLOAD_TYPE.T1.name) {
                const data = decode_T1(bytes, recvTime);

                if (Number.isFinite(data.index)) {
                    let val = data.index;
                    val *= PulseConversionValue; // leave as 1 if not needed
                    result.D[0].MD.push({ Id: normalizedIdMapping["water"], Val: val });
                }


            }
        }
    }
}

if (msg.dr && typeof msg.dr === "object") {
    if (Object.prototype.hasOwnProperty.call(msg.dr, "bandwidth")) {
        const v = Number(msg.dr.bandwidth);
        if (Number.isFinite(v)) result.D[0].MD.push({ Id: normalizedIdMapping["bandwidth"], Val: v });
    }
    if (Object.prototype.hasOwnProperty.call(msg.dr, "spreadFactor")) {
        const v = Number(msg.dr.spreadFactor);
        if (Number.isFinite(v)) result.D[0].MD.push({ Id: normalizedIdMapping["spreadfactor"], Val: v });
    }
}

for (const key of ["freq", "snr", "rssi"]) {
    if (!Object.prototype.hasOwnProperty.call(msg, key)) continue;
    const v = Number(msg[key]);
    if (!Number.isFinite(v)) continue;
    const id = normalizedIdMapping[key];
    if (id === undefined) continue;
    result.D[0].MD.push({ Id: id, Val: v });
}

global.set("mid", mid + 1);

msg.payload = result;
return msg;
